test.fill_query:
INSERT INTO bench_isect_early_empty_{n} SELECT
    if(number = 0,
        [[(0., 0.), (1., 0.), (1., 1.), (0., 1.), (0., 0.)]],
        if(number = 1,
            [[(10., 10.), (11., 10.), (11., 11.), (10., 11.), (10., 10.)]],
            [[(toFloat64(number), 0.), (toFloat64(number + 2), 0.),
              (toFloat64(number + 2), 2.), (toFloat64(number), 2.), (toFloat64(number), 0.)]]
        )
    )
FROM numbers({n})
